#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> spiralOrder(vector<vector<int>>& matrix) {
        vector<int> result;
        while (!matrix.empty()) {
            for (int i : matrix.front()) {
                result.push_back(i);
            }
            matrix.erase(matrix.begin());
            if (!matrix.empty() && !matrix.front().empty()) {
                for (auto& row : matrix) {
                    result.push_back(row.back());
                    row.pop_back();
                }
            }
            if (!matrix.empty()) {
                auto back = matrix.back();
                reverse(back.begin(), back.end());
                result.insert(result.end(), back.begin(), back.end());
                matrix.pop_back();
            }
            if (!matrix.empty() && !matrix.front().empty()) {
                for (auto it = matrix.rbegin(); it != matrix.rend(); ++it) {
                    result.push_back((*it).front());
                    (*it).erase((*it).begin());
                }
            }
        }
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int m, n;
    cin >> m >> n;
    vector<vector<int>> matrix(m, vector<int>(n));
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            cin >> matrix[i][j];
        }
    }
    Solution sol;
    vector<int> ans = sol.spiralOrder(matrix);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
